<template>
  <div class="fu-input-wrapper" :style="{ width: formWrapperWidth }">
    <!-- Label -->
    <label v-if="label" class="fu-input-label" :for="inputId">
      {{ label }}
      <span v-if="required" class="fu-input-required">*</span>
    </label>

    <div
      class="fu-input-container"
      :class="[`fu-input--${size}`, `fu-input--${variant}`, { 'fu-input--error': error }]"
    >
      <!-- Left Slot -->
      <div v-if="$slots.left" class="fu-input-icon fu-input-icon--left">
        <slot name="left" />
      </div>

      <!-- Input -->
      <input
        v-bind="$attrs"
        class="fu-input"
        :id="inputId"
        :name="inputName"
        :type="type"
        :placeholder="placeholder"
        :disabled="disabled"
        :required="required"
        :aria-invalid="!!error"
        :aria-describedby="error ? `${inputId}-error` : undefined"
        :inputmode="computedInputMode"
        :min="type === 'number' ? min : undefined"
        :max="type === 'number' ? max : undefined"
        :step="type === 'number' ? step : undefined"
        v-model="innerValue"
      />

      <!-- Right Slot -->
      <div v-if="$slots.right" class="fu-input-icon fu-input-icon--right">
        <slot name="right" />
      </div>
    </div>

    <!-- Error -->
    <span v-if="error" class="fu-input-error" :id="`${inputId}-error`">
      {{ error }}
    </span>
  </div>
</template>

<script setup lang="ts">
import { ref, watch, computed } from "vue";

interface Props {
  modelValue?: string | number;
  label?: string;
  placeholder?: string;
  type?: "text" | "email" | "password" | "number" | "tel" | "url" | "search";
  size?: "sm" | "md" | "lg";
  variant?: "subtle" | "outline" | "plain";
  disabled?: boolean;
  error?: string | null;
  min?: number;
  max?: number;
  step?: number;
  required?: boolean;
  formWrapperWidth?: string;

  id?: string;
  name?: string;

  /* MASKING */
  mask?: "phone" | "card" | "currency" | "custom" | null;
  maskPattern?: string;
}

const props = withDefaults(defineProps<Props>(), {
  modelValue: "",
  label: "",
  placeholder: "",
  type: "text",
  size: "sm",
  variant: "outline",
  disabled: false,
  error: null,
  min: undefined,
  max: undefined,
  step: undefined,
  required: false,
  formWrapperWidth: "fit-content",

  id: undefined,
  name: undefined,

  mask: null,
  maskPattern: "",
});

const emit = defineEmits<{
  (e: "update:modelValue", value: string | number): void;
}>();

/* -----------------------------------------------------------
   Stable ID
----------------------------------------------------------- */

const generatedId = `fu-input-${Math.random().toString(36).slice(2, 9)}`;
const inputId = computed(() => props.id || generatedId);
const inputName = computed(() => props.name || inputId.value);

/* -----------------------------------------------------------
   Input Mode Handling
----------------------------------------------------------- */

const computedInputMode = computed(() => {
  if (props.mask === "phone" || props.mask === "card") return "numeric";
  if (props.mask === "currency") return "decimal"; // allows decimal keyboard on mobile
  if (props.type === "number") return "numeric";
  return undefined;
});

/* -----------------------------------------------------------
   Mask Logic
----------------------------------------------------------- */

function applyMask(value: string): string {
  if (!props.mask) return value;

  switch (props.mask) {
    case "phone": {
      const digits = value.replace(/\D/g, "");
      return digits
        .slice(0, 11)
        .replace(/^(\d{5})(\d{0,6})$/, (_, a, b) => (b ? `${a} ${b}` : a));
    }

    case "card": {
      const digits = value.replace(/\D/g, "");
      return digits.slice(0, 16).replace(/(\d{4})(?=\d)/g, "$1 ");
    }

    case "currency": {
      // Allow digits, one decimal point, and up to 2 decimal places
      // Strip anything that isn't a digit or decimal point
      const sanitized = value.replace(/[^\d.]/g, "");

      // Prevent multiple decimal points
      const parts = sanitized.split(".");
      const intPart = parts[0] || "";
      const decPart = parts.length > 1 ? "." + parts[1].slice(0, 2) : "";

      // Format the integer part with thousands separators
      const formattedInt = intPart
        ? new Intl.NumberFormat("en-GB").format(Number(intPart))
        : "";

      // If user is actively typing a decimal (ends with "." or has decimal digits),
      // preserve that so they can continue typing
      return formattedInt + decPart;
    }

    case "custom": {
      if (!props.maskPattern) return value;
      const digits = value.replace(/\D/g, "");
      let i = 0;
      return props.maskPattern.replace(/#/g, () => digits[i++] || "");
    }

    default:
      return value;
  }
}

/** Strip mask formatting to get the raw underlying value */
function getRawValue(value: string): string {
  if (!props.mask) return value;
  if (props.mask === "currency") {
    // Keep digits and decimal point — strip thousands separators only
    return value.replace(/[^\d.]/g, "");
  }
  // For phone, card, custom: raw is just digits
  return value.replace(/\D/g, "");
}

/* -----------------------------------------------------------
   v-model Sync
   - innerValue holds the *masked* string for display
   - emit sends the *raw* (unmasked) value to the parent
----------------------------------------------------------- */

const innerValue = ref(applyMask(String(props.modelValue ?? "")));

watch(
  () => props.modelValue,
  (val) => {
    const masked = applyMask(String(val ?? ""));
    if (masked !== innerValue.value) {
      innerValue.value = masked;
    }
  }
);

watch(innerValue, (val) => {
  const masked = applyMask(String(val));

  if (masked !== val) {
    innerValue.value = masked;
    return;
  }

  emit("update:modelValue", getRawValue(masked));
});
</script>

<style scoped lang="scss">
@import "./FusionTextInput.scss";
</style>
